INSERT INTO leave_types (id, code, name, category, max_days, deductible, credit_source, requires_medical_after_days, filing_deadline_days, deadline_is_hard, detail_schema, required_documents, approval_flow, annual_reset, expires, is_custom, active, description, created_at, updated_at) VALUES ('1', 'VL', 'Vacation Leave', 'regular', NULL, '1', 'vacation', NULL, '5', '0', '[{"name":"location","label":"To be spent","type":"radio","required":true,"options":{"within_ph":"Within the Philippines","abroad":"Abroad"}},{"name":"location_specify","label":"Specify location","type":"text","required":true}]', '[]', '["department_head","hr","mayor"]', '0', '0', '0', '1', 'Deductible from Vacation Leave credits. File at least 5 days before effectivity whenever possible.', '2026-07-12 12:55:29', '2026-07-12 12:55:29');
INSERT INTO leave_types (id, code, name, category, max_days, deductible, credit_source, requires_medical_after_days, filing_deadline_days, deadline_is_hard, detail_schema, required_documents, approval_flow, annual_reset, expires, is_custom, active, description, created_at, updated_at) VALUES ('2', 'FL', 'Mandatory / Forced Leave', 'regular', '5', '1', 'vacation', NULL, '0', '0', '[{"name":"location","label":"To be spent","type":"radio","required":true,"options":{"within_ph":"Within the Philippines","abroad":"Abroad"}}]', '[]', '["department_head","hr","mayor"]', '1', '0', '0', '1', 'Five (5) days annually per CSC rules; deducted from VL credits; tracked automatically per year.', '2026-07-12 12:55:29', '2026-07-12 12:55:29');
INSERT INTO leave_types (id, code, name, category, max_days, deductible, credit_source, requires_medical_after_days, filing_deadline_days, deadline_is_hard, detail_schema, required_documents, approval_flow, annual_reset, expires, is_custom, active, description, created_at, updated_at) VALUES ('3', 'SL', 'Sick Leave', 'regular', NULL, '1', 'sick', '2', '0', '0', '[{"name":"confinement","label":"Where","type":"radio","required":true,"options":{"hospital":"In Hospital","outpatient":"Out Patient"}},{"name":"illness","label":"Specify illness","type":"text","required":true}]', '[{"type":"medical_certificate","label":"Medical Certificate","rule":{"days_gt":2}}]', '["department_head","hr","mayor"]', '0', '0', '0', '1', 'Deductible from Sick Leave credits. Medical certificate required beyond the configured day threshold; late filing after return captures a reason.', '2026-07-12 12:55:29', '2026-07-12 12:55:29');
INSERT INTO leave_types (id, code, name, category, max_days, deductible, credit_source, requires_medical_after_days, filing_deadline_days, deadline_is_hard, detail_schema, required_documents, approval_flow, annual_reset, expires, is_custom, active, description, created_at, updated_at) VALUES ('4', 'ML', 'Maternity Leave', 'special', '105', '0', NULL, NULL, '0', '0', '[{"name":"expected_delivery","label":"Expected\/Actual date of delivery","type":"date","required":true},{"name":"extension","label":"Availing additional extension (RA 11210)","type":"checkbox","required":false}]', '[{"type":"pregnancy_proof","label":"Proof of pregnancy (ultrasound)","rule":"always"},{"type":"medical_certificate","label":"Medical Certificate","rule":"always"}]', '["hr","mayor"]', '0', '0', '0', '1', '105 days per RA 11210, CSC compliant; extension where applicable.', '2026-07-12 12:55:29', '2026-07-12 12:55:29');
INSERT INTO leave_types (id, code, name, category, max_days, deductible, credit_source, requires_medical_after_days, filing_deadline_days, deadline_is_hard, detail_schema, required_documents, approval_flow, annual_reset, expires, is_custom, active, description, created_at, updated_at) VALUES ('5', 'PL', 'Paternity Leave', 'special', '7', '0', NULL, NULL, '0', '0', '[]', '[{"type":"birth_certificate","label":"Child''s Birth Certificate","rule":"always"},{"type":"marriage_certificate","label":"Marriage Certificate","rule":"always"},{"type":"medical_document","label":"Medical documents","rule":"optional"}]', '["department_head","hr","mayor"]', '0', '0', '0', '1', 'Seven (7) days for married male employees, per RA 8187.', '2026-07-12 12:55:29', '2026-07-12 12:55:29');
