-- LGU Alicia LMS — reference schema + baseline seed (SQLite dialect)
-- Canonical schema lives in database/migrations (engine-portable).
-- For MySQL deployment, run: php artisan migrate --seed  (see docs/Deployment.md)
-- Or generate a MySQL dump on the server: php artisan schema:dump

CREATE TABLE "activity_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "method" varchar not null, "path" varchar not null, "route_name" varchar, "ip" varchar not null, "user_agent" text, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);

CREATE TABLE "approvals" ("id" integer primary key autoincrement not null, "leave_request_id" integer not null, "step_no" integer not null, "role_slug" varchar not null, "approver_id" integer, "action" varchar not null default 'pending', "comments" text, "days_with_pay" numeric, "days_without_pay" numeric, "certified_balances" text, "signature" varchar, "acted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("leave_request_id") references "leave_requests"("id") on delete cascade, foreign key("approver_id") references "users"("id") on delete set null);

CREATE TABLE "archives" ("id" integer primary key autoincrement not null, "archivable_type" varchar not null, "archivable_id" integer not null, "snapshot" text not null, "archived_by" integer, "restored_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("archived_by") references "users"("id") on delete set null);

CREATE TABLE "audit_logs" ("id" integer primary key autoincrement not null, "user_id" integer, "role_snapshot" varchar, "action" varchar not null, "auditable_type" varchar, "auditable_id" integer, "old_values" text, "new_values" text, "ip" varchar, "user_agent" text, "url" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);

CREATE TABLE "authorized_devices" ("id" integer primary key autoincrement not null, "ip_address" varchar not null, "hostname" varchar not null, "mac_address" varchar, "description" varchar, "status" varchar not null default 'active', "registered_by" integer, "last_active_at" datetime, "archived_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("registered_by") references "users"("id") on delete set null);

CREATE TABLE "blocked_ips" ("id" integer primary key autoincrement not null, "ip" varchar not null, "reason" varchar not null, "source" varchar not null default 'auto', "blocked_by" integer, "expires_at" datetime, "active" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, foreign key("blocked_by") references "users"("id") on delete set null);

CREATE TABLE "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));

CREATE TABLE "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));

CREATE TABLE "departments" ("id" integer primary key autoincrement not null, "name" varchar not null, "code" varchar not null, "head_user_id" integer, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("head_user_id") references "users"("id") on delete set null);

CREATE TABLE "employee_profiles" ("id" integer primary key autoincrement not null, "user_id" integer not null, "employee_no" varchar not null, "first_name" varchar not null, "middle_name" varchar, "last_name" varchar not null, "gender" varchar, "civil_status" varchar, "birth_date" date, "contact_no" varchar, "address" varchar, "salary" numeric not null default '0', "department_id" integer, "position_id" integer, "employment_status" varchar not null default 'permanent', "date_hired" date, "signature_path" varchar, "is_solo_parent" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("department_id") references "departments"("id") on delete restrict, foreign key("position_id") references "positions"("id") on delete restrict);

CREATE TABLE "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);

CREATE TABLE "failed_logins" ("id" integer primary key autoincrement not null, "identifier" varchar not null, "user_id" integer, "ip" varchar not null, "user_agent" text, "reason" varchar not null, "occurred_at" datetime not null, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);

CREATE TABLE "holidays" ("id" integer primary key autoincrement not null, "date" date not null, "name" varchar not null, "scope" varchar not null default 'national', "created_at" datetime, "updated_at" datetime);

CREATE TABLE "intrusion_logs" ("id" integer primary key autoincrement not null, "category" varchar not null, "severity" varchar not null default 'medium', "route" varchar, "method" varchar, "payload_excerpt" text, "matched_rule" varchar, "ip" varchar not null, "user_agent" text, "user_id" integer, "handled" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete set null);

CREATE TABLE "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));

CREATE TABLE "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);

CREATE TABLE "leave_balances" ("id" integer primary key autoincrement not null, "user_id" integer not null, "leave_type_id" integer not null, "earned" numeric not null default '0', "used" numeric not null default '0', "balance" numeric not null default '0', "last_accrued_period" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("leave_type_id") references "leave_types"("id") on delete cascade);

CREATE TABLE "leave_history" ("id" integer primary key autoincrement not null, "user_id" integer not null, "leave_type_id" integer not null, "leave_request_id" integer, "entry_type" varchar not null, "days" numeric not null, "balance_after" numeric not null, "period" varchar, "remarks" varchar, "actor_id" integer, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("leave_type_id") references "leave_types"("id") on delete cascade, foreign key("leave_request_id") references "leave_requests"("id") on delete set null, foreign key("actor_id") references "users"("id") on delete set null);

CREATE TABLE "leave_request_documents" ("id" integer primary key autoincrement not null, "leave_request_id" integer not null, "type" varchar not null, "original_name" varchar not null, "path" varchar not null, "hash" varchar not null, "size" integer not null, "mime" varchar not null, "uploaded_by" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("leave_request_id") references "leave_requests"("id") on delete cascade, foreign key("uploaded_by") references "users"("id"));

CREATE TABLE "leave_requests" ("id" integer primary key autoincrement not null, "reference_no" varchar not null, "user_id" integer not null, "leave_type_id" integer not null, "date_filed" date not null, "start_date" date not null, "end_date" date not null, "working_days" numeric not null, "details" text, "purpose" text, "commutation" tinyint(1) not null default '0', "status" varchar not null default 'pending', "current_step" integer not null default '0', "is_late_filing" tinyint(1) not null default '0', "late_filing_reason" varchar, "filing_warnings" text, "hr_override" tinyint(1) not null default '0', "hr_override_reason" varchar, "days_with_pay" numeric, "days_without_pay" numeric, "disapproval_reason" varchar, "office_snapshot" varchar, "position_snapshot" varchar, "salary_snapshot" numeric, "applicant_signature" varchar, "decided_at" datetime, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade, foreign key("leave_type_id") references "leave_types"("id") on delete restrict);

CREATE TABLE "leave_types" ("id" integer primary key autoincrement not null, "code" varchar not null, "name" varchar not null, "category" varchar not null default 'regular', "max_days" numeric, "deductible" tinyint(1) not null default '0', "credit_source" varchar, "requires_medical_after_days" integer, "filing_deadline_days" integer not null default '0', "deadline_is_hard" tinyint(1) not null default '0', "detail_schema" text, "required_documents" text, "approval_flow" text, "annual_reset" tinyint(1) not null default '0', "expires" tinyint(1) not null default '0', "is_custom" tinyint(1) not null default '0', "active" tinyint(1) not null default '1', "description" text, "created_at" datetime, "updated_at" datetime);

CREATE TABLE "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);

CREATE TABLE "notifications" ("id" varchar not null, "type" varchar not null, "notifiable_type" varchar not null, "notifiable_id" integer not null, "data" text not null, "read_at" datetime, "created_at" datetime, "updated_at" datetime, primary key ("id"));

CREATE TABLE "otp_codes" ("id" integer primary key autoincrement not null, "user_id" integer not null, "code_hash" varchar not null, "purpose" varchar not null default 'login', "expires_at" datetime not null, "consumed_at" datetime, "attempts" integer not null default '0', "ip" varchar, "created_at" datetime, "updated_at" datetime, foreign key("user_id") references "users"("id") on delete cascade);

CREATE TABLE "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));

CREATE TABLE "permission_role" ("permission_id" integer not null, "role_id" integer not null, foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("role_id") references "roles"("id") on delete cascade, primary key ("permission_id", "role_id"));

CREATE TABLE "permission_user" ("permission_id" integer not null, "user_id" integer not null, "type" varchar not null default 'allow', foreign key("permission_id") references "permissions"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, primary key ("permission_id", "user_id"));

CREATE TABLE "permissions" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "module" varchar not null, "description" varchar, "created_at" datetime, "updated_at" datetime);

CREATE TABLE "personal_access_tokens" ("id" integer primary key autoincrement not null, "tokenable_type" varchar not null, "tokenable_id" integer not null, "name" text not null, "token" varchar not null, "abilities" text, "last_used_at" datetime, "expires_at" datetime, "created_at" datetime, "updated_at" datetime);

CREATE TABLE "positions" ("id" integer primary key autoincrement not null, "title" varchar not null, "salary_grade" varchar, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime);

CREATE TABLE "role_user" ("role_id" integer not null, "user_id" integer not null, foreign key("role_id") references "roles"("id") on delete cascade, foreign key("user_id") references "users"("id") on delete cascade, primary key ("role_id", "user_id"));

CREATE TABLE "roles" ("id" integer primary key autoincrement not null, "name" varchar not null, "slug" varchar not null, "description" varchar, "parent_id" integer, "is_system" tinyint(1) not null default '0', "created_at" datetime, "updated_at" datetime, foreign key("parent_id") references "roles"("id") on delete set null);

CREATE TABLE "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));

CREATE TABLE "system_settings" ("id" integer primary key autoincrement not null, "key" varchar not null, "value" text, "type" varchar not null default 'string', "group" varchar not null default 'general', "description" varchar, "created_at" datetime, "updated_at" datetime);

CREATE TABLE "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "username" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "status" varchar not null default 'active', "blocked_until" datetime, "blocked_reason" varchar, "failed_attempts" integer not null default '0', "must_change_password" tinyint(1) not null default '0', "password_changed_at" datetime, "last_login_at" datetime, "last_login_ip" varchar, "remember_token" varchar, "deleted_at" datetime, "created_at" datetime, "updated_at" datetime);

